            <button style="width:100%;padding:8px;background:linear-gradient(135deg,#D4956E,#A0623C);color:#fff;border:none;border-radius:9px;font-weight:800;font-size:0.75rem;cursor:pointer;letter-spacing:0.02em;">Buy Now →</button>
