          <button class="subs-filter" onclick="filterSubsTable(this,'late')" style="padding:7px 16px;border-radius:20px;border:1.5px solid #fecaca;background:#fee2e2;color:#dc2626;cursor:pointer;font-family:'DM Sans',sans-serif;font-weight:700;font-size:0.78rem;">Late / Overdue</button>
