    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:6px;">
      <h2 class="modal-title" style="margin:0;">📊 Create a Poll</h2>
      <button onclick="closeModal('modal-create-poll')" style="background:none;border:none;cursor:pointer;font-size:1.3rem;color:var(--text-dim);">✕</button>
    </div>
