      if(document.getElementById('ev-res-date')) document.getElementById('ev-res-date').value = '';
      if(document.getElementById('ev-res-time')) document.getElementById('ev-res-time').value = '';
      if(document.getElementById('ev-res-location')) document.getElementById('ev-res-location').value = '';
      if(document.getElementById('ev-res-perks')) document.getElementById('ev-res-perks').value = '';
