      if(document.getElementById('bday-announcement-fee')) document.getElementById('bday-announcement-fee').style.display = 'none';
      if(document.getElementById('bday-new-total')) document.getElementById('bday-new-total').style.display = 'none';
      var bdaySlider = document.getElementById('ev-bday-announcement-slider'); if(bdaySlider) bdaySlider.style.background = 'var(--cream3)';
      var bdayKnob = document.getElementById('ev-bday-announcement-knob'); if(bdayKnob) bdayKnob.style.transform = 'translateX(0)';
      if(document.getElementById('birthday-block')) document.getElementById('birthday-block').style.display = 'none';
